/**
 * Defines where the element should appear horizontally in the viewport.
 */
export const ScrollToInline = {
    /**
     * Aligns the element's start edge (left in LTR) to the viewport's start.
     */
    START: 'start',

    /**
     * Aligns the element horizontally in the center of the viewport.
     */
    CENTER: 'center',

    /**
     * Aligns the element's end edge (right in LTR) to the viewport's end.
     */
    END: 'end',

    /**
     * Scrolls the minimal horizontal distance necessary to bring the element into view.
     */
    NEAREST: 'nearest'
};
